// Нормалізуємо дані заявки. Інструкції для моделі — у ноді «Gemini — аналіз заявки».
const b = ($json.body && typeof $json.body === 'object') ? $json.body : $json;

function pick(...keys) {
  for (const k of keys) {
    if (b[k] !== undefined && b[k] !== null && b[k] !== '') return b[k];
  }
  return '';
}

const interestRaw = b.interest !== undefined ? b.interest : pick('interest', 'request');
const interest = Array.isArray(interestRaw) ? interestRaw.join(', ') : String(interestRaw || '');

const lead = {
  date: new Date().toISOString().slice(0, 16).replace('T', ' '),
  name: String(pick('name')),
  phone: String(pick('phone')),
  object_type: String(pick('object_type', 'object')),
  area: String(pick('area')),
  stage: String(pick('stage')),
  interest: interest,
  comment: String(pick('comment')),
  source: String(pick('source') || 'gravity-website')
};

const promptText = [
  `Імʼя: ${lead.name}`,
  `Телефон: ${lead.phone}`,
  `Тип обʼєкта: ${lead.object_type}`,
  `Площа: ${lead.area} м²`,
  `Стадія ремонту: ${lead.stage}`,
  `Що цікавить: ${lead.interest}`,
  `Коментар: ${lead.comment}`
].join('\n');

return [{ json: { ...lead, promptText } }];

// Розбираємо відповідь Gemini і будуємо текст для Telegram.
const lead = $('Нормалізувати заявку').item.json;

let ai = { solution_type: 'консультація', summary: 'AI не зміг розібрати заявку — потрібна ручна перевірка.', next_step: 'Передзвонити клієнту та уточнити деталі.' };
try {
  const raw = (typeof $json.text === 'string') ? $json.text : '';
  const a = raw.indexOf('{');
  const b = raw.lastIndexOf('}');
  if (a >= 0 && b > a) {
    const parsed = JSON.parse(raw.slice(a, b + 1));
    if (parsed && parsed.solution_type) ai = parsed;
  } else if ($json.output && $json.output.solution_type) {
    ai = $json.output;
  }
} catch (e) {
  // лишаємо fallback ai
}

const tagMap = { professional: 'professional', wireless: 'wireless' };
const tag = tagMap[ai.solution_type] || 'консультація';

const tgMessage = [
  '🔔 Нова заявка з сайту Gravity',
  '',
  `👤 Клієнт: ${lead.name}`,
  `📞 Телефон: ${lead.phone}`,
  `🏠 Обʼєкт: ${lead.object_type}, ${lead.area} м²`,
  `🛠 Стадія: ${lead.stage}`,
  `🎯 Запит: ${lead.interest}`,
  lead.comment ? `💬 Коментар: ${lead.comment}` : null,
  '',
  `🤖 Тип заявки: ${ai.solution_type}`,
  `🧠 Висновок AI: ${ai.summary}`,
  '',
  `➡️ Наступний крок: ${ai.next_step}`,
  '',
  `#заявка #${tag}`
].filter(Boolean).join('\n');

return [{ json: { solution_type: ai.solution_type, summary: ai.summary, next_step: ai.next_step, tgMessage } }];
